import{_ as e,o as a,c as n,a3 as r}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"Product Roadmap","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Product Roadmap | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/getting-started/product-roadmap"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Product Roadmap | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/getting-started/product-roadmap"}]]},"headers":[],"relativePath":"getting-started/product-roadmap.md","filePath":"getting-started/product-roadmap.md","lastUpdated":1784076469000}'),o={name:"getting-started/product-roadmap.md"};function d(i,t,l,s,h,p){return a(),n("div",null,[...t[0]||(t[0]=[r('<h1 id="product-roadmap" tabindex="-1">Product Roadmap <a class="header-anchor" href="#product-roadmap" aria-label="Permalink to &quot;Product Roadmap&quot;">​</a></h1><p>Long-term direction of the platform: evolution from a CRM into a complete SaaS ERP. Modules should be implemented in the order below unless business priorities require otherwise.</p><blockquote><p><strong>Architecture Policy</strong></p><p>The platform foundation (authentication, tenancy, RBAC, billing, marketplace, settings, audit logging, and module licensing) is <strong>frozen</strong>. New functionality must be implemented as modules using the <a href="/developer-guide/module-development">Module Development Standard</a>. Architectural changes should only be made for critical security issues, production defects, or platform-wide improvements.</p><p>See <a href="/getting-started/platform-freeze">architecture/platform-freeze.md</a>.</p></blockquote><hr><h2 id="phase-1-—-crm-completed-in-progress" tabindex="-1">Phase 1 — CRM (Completed / In Progress) <a class="header-anchor" href="#phase-1-—-crm-completed-in-progress" aria-label="Permalink to &quot;Phase 1 — CRM (Completed / In Progress)&quot;">​</a></h2><p>The CRM is the foundation of the platform and is the first functional area delivered.</p><h3 id="completed" tabindex="-1">Completed <a class="header-anchor" href="#completed" aria-label="Permalink to &quot;Completed&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Module / capability</th><th>Status</th></tr></thead><tbody><tr><td><a href="/user-guide/leads-overview">Leads</a></td><td>✅ Completed (Sprint 2 UX: Kanban, KPIs, export, convert stub, independent status/priority)</td></tr><tr><td><a href="/user-guide/tasks-overview">Tasks</a></td><td>✅ Completed (Sprint 2 UX: board, KPIs, waiting status, due-date permission, comments/history)</td></tr><tr><td>In-app notifications + due digests</td><td>✅ Completed (mail + database; polling; Reverb deferred)</td></tr><tr><td>Tenant dashboard widgets</td><td>✅ Completed (module/permission/assignee scoped; no calendar until Calendar module)</td></tr></tbody></table><h3 id="planned" tabindex="-1">Planned <a class="header-anchor" href="#planned" aria-label="Permalink to &quot;Planned&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Module</th><th>Status</th></tr></thead><tbody><tr><td>Contacts</td><td>Planned (unlocks full lead convert)</td></tr><tr><td>Companies</td><td>Planned</td></tr><tr><td>Calendar</td><td>Planned (calendar dashboard widget)</td></tr><tr><td>Activities</td><td>Planned</td></tr></tbody></table><p><strong>Goal:</strong> Provide a complete customer relationship management experience with lead tracking, task management, customer records, scheduling, and activity history.</p><hr><h2 id="phase-2-—-sales" tabindex="-1">Phase 2 — Sales <a class="header-anchor" href="#phase-2-—-sales" aria-label="Permalink to &quot;Phase 2 — Sales&quot;">​</a></h2><p>Once CRM is complete, extend it into a full sales workflow.</p><table tabindex="0"><thead><tr><th>Module</th><th>Status</th></tr></thead><tbody><tr><td>Opportunities</td><td>Planned</td></tr><tr><td>Sales Pipeline</td><td>Planned</td></tr><tr><td>Quotations</td><td>Planned</td></tr><tr><td>Contracts</td><td>Planned</td></tr></tbody></table><p><strong>Goal:</strong> Manage the entire sales lifecycle from opportunity creation through quotation, negotiation, and contract execution.</p><hr><h2 id="phase-3-—-billing" tabindex="-1">Phase 3 — Billing <a class="header-anchor" href="#phase-3-—-billing" aria-label="Permalink to &quot;Phase 3 — Billing&quot;">​</a></h2><p>Build a comprehensive billing and invoicing solution that integrates with the existing Marketplace and subscription platform.</p><table tabindex="0"><thead><tr><th>Module</th><th>Status</th></tr></thead><tbody><tr><td>Invoices</td><td>Planned</td></tr><tr><td>Estimates</td><td>Planned</td></tr><tr><td>Credit Notes</td><td>Planned</td></tr><tr><td>Payments</td><td>Planned</td></tr></tbody></table><p><strong>Goal:</strong> Provide complete customer billing, payment tracking, and financial document management.</p><blockquote><p><strong>Note:</strong> Platform billing (module subscriptions, consolidated billing, gateway abstraction) already exists under Central. Phase 3 modules are <strong>tenant product billing</strong> (customer-facing invoices/payments), not a redesign of the Marketplace billing engine.</p></blockquote><hr><h2 id="phase-4-—-purchasing" tabindex="-1">Phase 4 — Purchasing <a class="header-anchor" href="#phase-4-—-purchasing" aria-label="Permalink to &quot;Phase 4 — Purchasing&quot;">​</a></h2><p>Introduce purchasing and vendor management.</p><table tabindex="0"><thead><tr><th>Module</th><th>Status</th></tr></thead><tbody><tr><td>Vendors</td><td>Planned</td></tr><tr><td>Purchase Orders</td><td>Planned</td></tr><tr><td>Expenses</td><td>Planned</td></tr></tbody></table><p><strong>Goal:</strong> Manage supplier relationships, procurement workflows, and operational expenses.</p><hr><h2 id="phase-5-—-inventory" tabindex="-1">Phase 5 — Inventory <a class="header-anchor" href="#phase-5-—-inventory" aria-label="Permalink to &quot;Phase 5 — Inventory&quot;">​</a></h2><p>Implement inventory and warehouse management.</p><table tabindex="0"><thead><tr><th>Module</th><th>Status</th></tr></thead><tbody><tr><td>Products</td><td>Planned</td></tr><tr><td>Categories</td><td>Planned</td></tr><tr><td>Warehouses</td><td>Planned</td></tr><tr><td>Stock Management</td><td>Planned</td></tr><tr><td>Stock Transfers</td><td>Planned</td></tr></tbody></table><p><strong>Goal:</strong> Provide inventory control, stock tracking, warehouse operations, and product management.</p><hr><h2 id="phase-6-—-finance" tabindex="-1">Phase 6 — Finance <a class="header-anchor" href="#phase-6-—-finance" aria-label="Permalink to &quot;Phase 6 — Finance&quot;">​</a></h2><p>Expand into accounting and financial reporting.</p><table tabindex="0"><thead><tr><th>Module</th><th>Status</th></tr></thead><tbody><tr><td>Accounts</td><td>Planned</td></tr><tr><td>Journals</td><td>Planned</td></tr><tr><td>General Ledger</td><td>Planned</td></tr><tr><td>Financial Reports</td><td>Planned</td></tr></tbody></table><p><strong>Goal:</strong> Provide the financial backbone required for a complete ERP solution.</p><hr><h2 id="phase-7-—-human-resources" tabindex="-1">Phase 7 — Human Resources <a class="header-anchor" href="#phase-7-—-human-resources" aria-label="Permalink to &quot;Phase 7 — Human Resources&quot;">​</a></h2><p>Implement workforce management.</p><table tabindex="0"><thead><tr><th>Module</th><th>Status</th></tr></thead><tbody><tr><td>Employees</td><td>Planned</td></tr><tr><td>Attendance</td><td>Planned</td></tr><tr><td>Leave Management</td><td>Planned</td></tr><tr><td>Payroll</td><td>Planned</td></tr></tbody></table><p><strong>Goal:</strong> Provide employee management, attendance tracking, leave workflows, and payroll processing.</p><hr><h2 id="future-expansion" tabindex="-1">Future Expansion <a class="header-anchor" href="#future-expansion" aria-label="Permalink to &quot;Future Expansion&quot;">​</a></h2><p>The platform architecture supports additional modules without requiring architectural refactoring. Candidates include:</p><ul><li>Assets</li><li>Projects</li><li>Help Desk</li><li>Knowledge Base</li><li>Documents</li><li>Manufacturing</li><li>Quality Assurance</li><li>Recruitment</li><li>Customer Portal</li><li>Vendor Portal</li><li>Business Intelligence &amp; Analytics</li><li>Workflow Automation</li><li>Marketing Automation</li><li>Email Campaigns</li><li>SMS &amp; WhatsApp Integrations</li><li>API &amp; Webhooks</li><li>AI Assistants</li><li>Multi-Branch Management</li><li>Multi-Currency Accounting</li><li>POS (Point of Sale)</li><li>E-Commerce Integrations</li></ul><p>These modules will follow the same Module Development Standard established by Leads and Tasks.</p><hr><h2 id="development-principles" tabindex="-1">Development Principles <a class="header-anchor" href="#development-principles" aria-label="Permalink to &quot;Development Principles&quot;">​</a></h2><p>Every module must:</p><ul><li>Follow the established platform architecture (<a href="/getting-started/platform-freeze">platform freeze</a>)</li><li>Respect module licensing and Marketplace activation</li><li>Enforce RBAC permissions</li><li>Maintain tenant isolation</li><li>Integrate with the shared settings framework where applicable</li><li>Generate audit and activity logs where applicable</li><li>Include automated testing (Pest and Playwright)</li><li>Pass manual browser QA</li><li>Update the Developer Guide, User Guide, API documentation, database documentation, testing documentation, and <a href="/changelog/">CHANGELOG</a> before being considered complete</li></ul><p>Full checklist: <a href="/developer-guide/module-development">Module Development Standard</a>.</p><hr><h2 id="long-term-vision" tabindex="-1">Long-Term Vision <a class="header-anchor" href="#long-term-vision" aria-label="Permalink to &quot;Long-Term Vision&quot;">​</a></h2><p>Evolve the platform into a modular, enterprise-grade SaaS ERP where organizations subscribe only to the modules they require. Each module integrates with the shared platform foundation while remaining independently licensable, maintainable, and scalable.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/getting-started/platform-freeze">Platform Architecture Freeze</a></li><li><a href="/developer-guide/module-development">Module Development Standard</a></li><li><a href="/developer-guide/entitlements">Entitlements</a></li><li><a href="/user-guide/leads-overview">Leads</a> · <a href="/user-guide/tasks-overview">Tasks</a></li></ul>',57)])])}const m=e(o,[["render",d]]);export{u as __pageData,m as default};
